import { Link } from 'react-router-dom';

function Home() {
  return (
    <div className="hero-section text-center text-white d-flex align-items-center">
      <div className="container">
        <h1 className="display-4 fw-bold">Emergency Help, Instantly</h1>
        <p className="lead">Trigger SOS, find hospitals, and connect blood donors in seconds.</p>
        <div className="d-flex flex-wrap justify-content-center gap-3 mt-4">
          <Link className="btn btn-danger btn-lg" to="/sos">SOS Alert</Link>
          <Link className="btn btn-light btn-lg" to="/hospitals">Find Hospitals</Link>
          <Link className="btn btn-outline-light btn-lg" to="/donors">Search Donors</Link>
        </div>
      </div>
    </div>
  );
}

export default Home;
